import React from 'react';
import { Link } from 'react-router-dom';
import { useTranslation } from 'react-i18next';
import { 
    Mail, 
    Phone, 
    MapPin, 
    Facebook, 
    Twitter, 
    Instagram, 
    Linkedin, 
    Youtube,
    ArrowRight,
    Heart,
    Sparkles,
    Globe,
    BookOpen,
    Users,
    Award,
    Target,
    Zap,
    Send,
    ChevronUp
} from 'lucide-react';

const Footer = () => {
    const { t } = useTranslation();

    // Scroll to top function
    const scrollToTop = () => {
        window.scrollTo({ top: 0, behavior: 'smooth' });
    };

    // Footer links data
    const quickLinks = [
        { name: t('footer.quickLinks.about') || 'About Us', path: '/about' },
        { name: t('footer.quickLinks.programs') || 'Programs', path: '/courses' },
        { name: t('footer.quickLinks.admissions') || 'Admissions', path: '/admissions' },
        { name: t('footer.quickLinks.contact') || 'Contact', path: '/contact' },
        { name: t('footer.quickLinks.news') || 'News & Events', path: '/news' },
        { name: t('footer.quickLinks.career') || 'Career', path: '/career' }
    ];

    const programs = [
        { name: t('footer.programs.webDev') || 'Web Development', path: '/courses/web-development' },
        { name: t('footer.programs.ai') || 'AI & Machine Learning', path: '/courses/ai-ml' },
        { name: t('footer.programs.cybersecurity') || 'Cybersecurity', path: '/courses/cybersecurity' },
        { name: t('footer.programs.dataScience') || 'Data Science', path: '/courses/data-science' },
        { name: t('footer.programs.blockchain') || 'Blockchain', path: '/courses/blockchain' },
        { name: t('footer.programs.iot') || 'IoT Development', path: '/courses/iot' }
    ];

    const resources = [
        { name: t('footer.resources.library') || 'Digital Library', path: '/library' },
        { name: t('footer.resources.blog') || 'Tech Blog', path: '/blog' },
        { name: t('footer.resources.tutorials') || 'Free Tutorials', path: '/tutorials' },
        { name: t('footer.resources.webinars') || 'Webinars', path: '/webinars' },
        { name: t('footer.resources.downloads') || 'Downloads', path: '/downloads' },
        { name: t('footer.resources.faq') || 'FAQ', path: '/faq' }
    ];

    const socialLinks = [
        { icon: Facebook, color: 'from-blue-600 to-blue-700', hoverColor: 'hover:from-blue-700 hover:to-blue-800', url: '#' },
        { icon: Twitter, color: 'from-sky-500 to-sky-600', hoverColor: 'hover:from-sky-600 hover:to-sky-700', url: '#' },
        { icon: Instagram, color: 'from-pink-500 to-purple-600', hoverColor: 'hover:from-pink-600 hover:to-purple-700', url: '#' },
        { icon: Linkedin, color: 'from-blue-700 to-blue-800', hoverColor: 'hover:from-blue-800 hover:to-blue-900', url: '#' },
        { icon: Youtube, color: 'from-red-600 to-red-700', hoverColor: 'hover:from-red-700 hover:to-red-800', url: '#' }
    ];

    const stats = [
        { icon: Users, number: '10,000+', label: t('footer.stats.students') || 'Students' },
        { icon: BookOpen, number: '50+', label: t('footer.stats.courses') || 'Courses' },
        { icon: Award, number: '95%', label: t('footer.stats.placement') || 'Placement Rate' },
        { icon: Globe, number: '25+', label: t('footer.stats.countries') || 'Countries' }
    ];

    return (
        <footer className="relative bg-gradient-to-br from-slate-900 via-blue-900 to-purple-900 text-white overflow-hidden">
            {/* Animated Background Elements */}
            <div className="absolute inset-0 overflow-hidden">
                {/* Floating Orbs */}
                <div className="absolute top-20 left-10 w-32 h-32 bg-blue-500/10 rounded-full blur-xl animate-pulse"></div>
                <div className="absolute top-40 right-20 w-48 h-48 bg-purple-500/10 rounded-full blur-xl animate-pulse delay-300"></div>
                <div className="absolute bottom-20 left-1/4 w-24 h-24 bg-pink-500/10 rounded-full blur-xl animate-pulse delay-700"></div>

                {/* Floating Particles */}
                <div className="absolute top-0 left-0 w-full h-full">
                    {[...Array(20)].map((_, i) => (
                        <div
                            key={i}
                            className={`absolute w-1 h-1 bg-white/20 rounded-full animate-pulse`}
                            style={{
                                left: `${Math.random() * 100}%`,
                                top: `${Math.random() * 100}%`,
                                animationDelay: `${Math.random() * 3}s`,
                                animationDuration: `${2 + Math.random() * 3}s`
                            }}
                        ></div>
                    ))}
                </div>

                {/* Grid Pattern */}
                <div className="absolute inset-0 bg-[linear-gradient(rgba(255,255,255,0.02)_1px,transparent_1px),linear-gradient(90deg,rgba(255,255,255,0.02)_1px,transparent_1px)] bg-[size:50px_50px]"></div>
            </div>

            {/* Wave Divider */}
